-- ----------------------------------------------------------------------------
-- Loops: Table: Loops — build history and forward plan, carried as a first-class entity inside the model. Each row documents what new concept is introduced, what was witnessed, and (for planned rows) the next empirical question. Loops 62–67 are the corpus-scale research sweep + catalog expansion. Loops 68+ are the expansion encode waves: pre-register in DiscoveryHypotheses, encode via StudyImportTemplate, LoopReview at end of each turn before committing vocabulary.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS loops (
  loop_id                             TEXT                 PRIMARY KEY          -- Unique identifier: loop-01 through loop-10.
);
ALTER TABLE loops ADD COLUMN IF NOT EXISTS title TEXT;                                              -- Short title for what this loop adds to the domain model.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS status TEXT;                                             -- planned | in-progress | complete
ALTER TABLE loops ADD COLUMN IF NOT EXISTS new_concept TEXT;                                        -- The new first-class domain concept introduced this loop.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS domain_question TEXT;                                    -- The natural-language question this loop's concept answers FROM the domain data.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS mock_data_note TEXT;                                     -- What the seed data is designed to show.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS next_suggestion TEXT;                                    -- Suggestion for the next loop, written after witnessing the DAG at this loop's end.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS tradition_id TEXT;                                       -- FK → ResearchTraditions.TraditionId. The scholarly tradition whose conceptual vocabulary this loop primarily draws on — tracks which tradition has driven each stage of the instrument's development.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS commit_hash TEXT;                                        -- Full git SHA where this loop row first landed in effortless-rulebook.json — the replay anchor for this turn of the Leopold loop.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS commit_date DATE;                                        -- ISO date (YYYY-MM-DD) of the commit where this loop landed.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS commit_message TEXT;                                     -- Git commit subject line for this loop's landing commit.
ALTER TABLE loops ADD COLUMN IF NOT EXISTS git_tag TEXT;                                            -- Optional milestone tag pointing at this loop's landing commit (sp-loop-milestone-*). Used for discovery replay without memorizing SHAs.
COMMENT ON TABLE loops IS 'Table: Loops — build history and forward plan, carried as a first-class entity inside the model. Each row documents what new concept is introduced, what was witnessed, and (for planned rows) the next empirical question. Loops 62–67 are the corpus-scale research sweep + catalog expansion. Loops 68+ are the expansion encode waves: pre-register in DiscoveryHypotheses, encode via StudyImportTemplate, LoopReview at end of each turn before committing vocabulary.';
COMMENT ON COLUMN loops.loop_id IS 'Unique identifier: loop-01 through loop-10.';
COMMENT ON COLUMN loops.title IS 'Short title for what this loop adds to the domain model.';
COMMENT ON COLUMN loops.status IS 'planned | in-progress | complete';
COMMENT ON COLUMN loops.new_concept IS 'The new first-class domain concept introduced this loop.';
COMMENT ON COLUMN loops.domain_question IS 'The natural-language question this loop''s concept answers FROM the domain data.';
COMMENT ON COLUMN loops.mock_data_note IS 'What the seed data is designed to show.';
COMMENT ON COLUMN loops.next_suggestion IS 'Suggestion for the next loop, written after witnessing the DAG at this loop''s end.';
COMMENT ON COLUMN loops.tradition_id IS 'FK → ResearchTraditions.TraditionId. The scholarly tradition whose conceptual vocabulary this loop primarily draws on — tracks which tradition has driven each stage of the instrument''s development.';
COMMENT ON COLUMN loops.commit_hash IS 'Full git SHA where this loop row first landed in effortless-rulebook.json — the replay anchor for this turn of the Leopold loop.';
COMMENT ON COLUMN loops.commit_date IS 'ISO date (YYYY-MM-DD) of the commit where this loop landed.';
COMMENT ON COLUMN loops.commit_message IS 'Git commit subject line for this loop''s landing commit.';
COMMENT ON COLUMN loops.git_tag IS 'Optional milestone tag pointing at this loop''s landing commit (sp-loop-milestone-*). Used for discovery replay without memorizing SHAs.';

-- ----------------------------------------------------------------------------
-- Studies: Table: Studies — a clinical or empirical study comparing two or more treatments for a condition, with patient cases stratified by a confounding variable. The top-level entity in the domain.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS studies (
  study_id                            TEXT                 PRIMARY KEY          -- Unique slug for this study (e.g. kidney-1986, berkeley-1973).
);
ALTER TABLE studies ADD COLUMN IF NOT EXISTS title TEXT;                                            -- Human-readable title of the study.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS source TEXT;                                           -- Citation or description of the original data source.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS source_url TEXT;                                       -- URL to the original source.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS publication_year INTEGER;                              -- Year the study was published. Used for temporal stratification and pre-registration dating.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS domain TEXT;                                           -- Research domain: medicine | epidemiology | social-science | education | legal | sports | economics | synthetic. Enables cross-domain SignalPurity stratification.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS is_synthetic BOOLEAN;                                  -- TRUE for constructed/counterfactual studies; FALSE for real published studies. Filters the corpus for empirical claims.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS tradition_id TEXT;                                     -- FK → ResearchTraditions.TraditionId. The scholarly tradition whose framing best characterizes this study's paradox type. Synthetic studies inherit the tradition of their conceptual origin.
ALTER TABLE studies ADD COLUMN IF NOT EXISTS primary_researcher_id TEXT;                            -- FK → Researchers.ResearcherId. The researcher most associated with first surfacing or canonically citing this study in the Simpson's Paradox literature.
COMMENT ON TABLE studies IS 'Table: Studies — a clinical or empirical study comparing two or more treatments for a condition, with patient cases stratified by a confounding variable. The top-level entity in the domain.';
COMMENT ON COLUMN studies.study_id IS 'Unique slug for this study (e.g. kidney-1986, berkeley-1973).';
COMMENT ON COLUMN studies.title IS 'Human-readable title of the study.';
COMMENT ON COLUMN studies.source IS 'Citation or description of the original data source.';
COMMENT ON COLUMN studies.source_url IS 'URL to the original source.';
COMMENT ON COLUMN studies.publication_year IS 'Year the study was published. Used for temporal stratification and pre-registration dating.';
COMMENT ON COLUMN studies.domain IS 'Research domain: medicine | epidemiology | social-science | education | legal | sports | economics | synthetic. Enables cross-domain SignalPurity stratification.';
COMMENT ON COLUMN studies.is_synthetic IS 'TRUE for constructed/counterfactual studies; FALSE for real published studies. Filters the corpus for empirical claims.';
COMMENT ON COLUMN studies.tradition_id IS 'FK → ResearchTraditions.TraditionId. The scholarly tradition whose framing best characterizes this study''s paradox type. Synthetic studies inherit the tradition of their conceptual origin.';
COMMENT ON COLUMN studies.primary_researcher_id IS 'FK → Researchers.ResearcherId. The researcher most associated with first surfacing or canonically citing this study in the Simpson''s Paradox literature.';

