-- ModelSummary: Table: ModelSummary — one row describing the epistemic coverage of this entire model instance. Aggregates across all TreatmentRankings to witness how many studies were examined, how many showed a full reversal, how many were explained, and the average paradox strength. The model holds a mirror to itself.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS model_summary (
  model_summary_id                    TEXT                 PRIMARY KEY          -- Unique identifier for this model instance.
);
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS real_study_count TEXT;                           -- Number of real (non-synthetic) published studies in the corpus.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS avg_signal_purity_reversal TEXT;                 -- Average SignalPurity across reversal studies (type A and B). Theorem predicts this must be < 0.5.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS avg_signal_purity_non_reversal TEXT;             -- Average SignalPurity across non-reversal studies (type C+, C-, D). Theorem predicts this must be >= 0.5 except edge cases.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS signal_purity_gap TEXT;                          -- Separation between reversal and non-reversal average SignalPurity. The larger this gap, the more discriminating the threshold at 0.5.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS medicine_study_count TEXT;                       -- Real published studies in the medicine domain.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS epidemiology_study_count TEXT;                   -- Real published studies in the epidemiology domain.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS other_domain_study_count TEXT;                   -- Real published studies outside medicine and epidemiology (sports, legal, education, social-science).
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS domain_diversity_note TEXT;                      -- Human-readable domain breakdown. Witnesses corpus diversity — a prerequisite for cross-domain SignalPurity claims.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS synthetic_phase_count INTEGER;                   -- Number of parameter grid points in SyntheticPhase. Refreshed from vw_phase_diagram_summary by 05b-customize-data.sql.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS phase_diagram_complete BOOLEAN;                  -- TRUE when all five DistortionType cells are populated in the synthetic phase grid. Refreshed from vw_phase_diagram_summary by 05b.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS phase_taxonomy_coverage TEXT;                    -- Type counts across the synthetic phase grid. Refreshed from vw_phase_diagram_summary by 05b.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS high_imbalance_sign_flip_threshold NUMERIC;      -- max_stratum_imbalance cutoff for geometry-controlled domain screening (loop-66). Set from corpus median by customize SQL.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS economics_high_imbalance_sign_flip_count NUMERIC;-- Sign-flip count among economics studies with max_stratum_imbalance >= threshold.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS epidemiology_high_imbalance_sign_flip_rate NUMERIC;-- Sign-flip rate among high-imbalance epidemiology studies.
