ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS sports_high_imbalance_sign_flip_rate NUMERIC;    -- Sign-flip rate among high-imbalance sports studies.
ALTER TABLE model_summary ADD COLUMN IF NOT EXISTS identity_cluster_witness_note TEXT;              -- Loop-80 identity layer witness rollup (customize SQL).
