-- ----------------------------------------------------------------------------
-- StratumVariables: Table: StratumVariables — one row per study, naming the variable that defines the strata and describing its causal role. A confounder affects both treatment assignment AND outcome; a mediator is downstream of treatment; a contested variable is one where the causal role is disputed. IsConfounder is derived from these two boolean flags.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS stratum_variables (
  stratum_variable_id                 TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-stone-size).
);
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS study TEXT;                                  -- FK to the parent Study.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS variable_name TEXT;                          -- The name of the stratifying variable (e.g. stone_size, department, age_group).
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS causal_role TEXT;                            -- The variable's causal role: 'confounder' (affects both assignment and outcome), 'mediator' (downstream of treatment), 'contested' (causal role disputed), 'unknown'.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS affects_treatment_assignment BOOLEAN;        -- TRUE if this variable causally influences which treatment a patient receives. Required for confounding.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS affects_outcome BOOLEAN;                     -- TRUE if this variable causally influences the outcome independently of treatment. Required for confounding.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS mechanism_note TEXT;                         -- Plain-language description of how this variable creates the confounding: why it affects both assignment and outcome.
ALTER TABLE stratum_variables ADD COLUMN IF NOT EXISTS conditioning_risk TEXT;                      -- The causal hazard posed by conditioning on this variable. Values: confounder (safe to condition — removes bias), mediator (conditioning blocks the causal path of interest — harmful), collider (conditioning opens a spurious backdoor — harmful), proxy (conditioning on a noisy proxy of the true confounder — risky), none (no conditioning risk identified). NULL means unclassified.
COMMENT ON TABLE stratum_variables IS 'Table: StratumVariables — one row per study, naming the variable that defines the strata and describing its causal role. A confounder affects both treatment assignment AND outcome; a mediator is downstream of treatment; a contested variable is one where the causal role is disputed. IsConfounder is derived from these two boolean flags.';
COMMENT ON COLUMN stratum_variables.stratum_variable_id IS 'Unique slug (e.g. kidney-1986-stone-size).';
COMMENT ON COLUMN stratum_variables.study IS 'FK to the parent Study.';
COMMENT ON COLUMN stratum_variables.variable_name IS 'The name of the stratifying variable (e.g. stone_size, department, age_group).';
COMMENT ON COLUMN stratum_variables.causal_role IS 'The variable''s causal role: ''confounder'' (affects both assignment and outcome), ''mediator'' (downstream of treatment), ''contested'' (causal role disputed), ''unknown''.';
COMMENT ON COLUMN stratum_variables.affects_treatment_assignment IS 'TRUE if this variable causally influences which treatment a patient receives. Required for confounding.';
COMMENT ON COLUMN stratum_variables.affects_outcome IS 'TRUE if this variable causally influences the outcome independently of treatment. Required for confounding.';
COMMENT ON COLUMN stratum_variables.mechanism_note IS 'Plain-language description of how this variable creates the confounding: why it affects both assignment and outcome.';
COMMENT ON COLUMN stratum_variables.conditioning_risk IS 'The causal hazard posed by conditioning on this variable. Values: confounder (safe to condition — removes bias), mediator (conditioning blocks the causal path of interest — harmful), collider (conditioning opens a spurious backdoor — harmful), proxy (conditioning on a noisy proxy of the true confounder — risky), none (no conditioning risk identified). NULL means unclassified.';

-- ----------------------------------------------------------------------------
-- TreatmentRankings: Table: TreatmentRankings — one row per treatment-pair comparison within a study. Derives the pooled winner, the per-stratum winner, and the IsReversal boolean. The paradox emerges here as a derived fact: IsReversal is true when the pooled winner and the per-stratum winner disagree.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS treatment_rankings (
  treatment_ranking_id                TEXT                 PRIMARY KEY          -- Unique slug (e.g. kidney-1986-A-vs-B).
);
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS study TEXT;                                 -- FK to the parent Study.
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS treatment_a TEXT;                           -- Label for the first treatment in the comparison (matches Treatments.TreatmentLabel).
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS treatment_b TEXT;                           -- Label for the second treatment in the comparison.
ALTER TABLE treatment_rankings ADD COLUMN IF NOT EXISTS adjustment_rationale TEXT;                  -- Human-authored note explaining why AdjustmentAppropriate is TRUE or FALSE for this study. Covers mediator/collider hazards, contested causal roles, and cases where geometric correction is valid but causal interpretation is uncertain.
COMMENT ON TABLE treatment_rankings IS 'Table: TreatmentRankings — one row per treatment-pair comparison within a study. Derives the pooled winner, the per-stratum winner, and the IsReversal boolean. The paradox emerges here as a derived fact: IsReversal is true when the pooled winner and the per-stratum winner disagree.';
COMMENT ON COLUMN treatment_rankings.treatment_ranking_id IS 'Unique slug (e.g. kidney-1986-A-vs-B).';
COMMENT ON COLUMN treatment_rankings.study IS 'FK to the parent Study.';
COMMENT ON COLUMN treatment_rankings.treatment_a IS 'Label for the first treatment in the comparison (matches Treatments.TreatmentLabel).';
COMMENT ON COLUMN treatment_rankings.treatment_b IS 'Label for the second treatment in the comparison.';
COMMENT ON COLUMN treatment_rankings.adjustment_rationale IS 'Human-authored note explaining why AdjustmentAppropriate is TRUE or FALSE for this study. Covers mediator/collider hazards, contested causal roles, and cases where geometric correction is valid but causal interpretation is uncertain.';

-- ----------------------------------------------------------------------------
-- InvariantChecks: Table: InvariantChecks — one row per algebraic invariant across the 40-study validation corpus. PassCount and FailCount are populated by run_invariant_checks() in 05b-customize-data.sql. Any critical FailCount > 0 breaks the build.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS invariant_checks (
  invariant_check_id                  TEXT                 PRIMARY KEY          -- Unique slug for this invariant (e.g. inv-balanced-alloc).
);
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS algebraic_statement TEXT;                     -- The mathematical assertion in compact symbolic form.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS natural_language TEXT;                        -- Plain-English statement of what property must hold and why it is an invariant of the model.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS source_table TEXT;                            -- The DAG table whose rows are checked (TreatmentRankings or StratumSummaries).
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS filter_expression TEXT;                       -- Condition selecting the universe of rows this invariant applies to. Empty means all rows.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS assertion_expression TEXT;                    -- The per-row condition that must be TRUE for every row in scope.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS sql_filter TEXT;                              -- Optional SQL WHERE clause that selects the universe of rows in scope for this invariant (e.g. distortion_type = 'D'). Empty string means all rows.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS sql_assertion TEXT;                           -- The SQL WHERE clause (without WHERE keyword) that counts PASSING rows from vw_treatment_rankings for this invariant. Used by run_invariant_checks() to evaluate each assertion dynamically from the rulebook table.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS pass_count INTEGER;                           -- Rows where the invariant holds. Populated by 05b-customize-data.sql from a live query against vw_treatment_rankings.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS fail_count INTEGER;                           -- Rows where the invariant is violated. Any FailCount > 0 is a build-breaking bug.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS severity TEXT;                                -- critical | warning — critical means any FailCount > 0 is a build-breaking bug.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS tradition_id TEXT;                            -- FK → ResearchTraditions.TraditionId. The tradition whose theoretical commitments this algebraic invariant protects — a failed invariant would falsify that tradition's key claim.
ALTER TABLE invariant_checks ADD COLUMN IF NOT EXISTS protects_conclusion TEXT;                     -- FK → Conclusions.ConclusionId. The conclusion whose witness depends on this invariant holding. If this invariant fails, that conclusion is undermined.
COMMENT ON TABLE invariant_checks IS 'Table: InvariantChecks — one row per algebraic invariant across the 40-study validation corpus. PassCount and FailCount are populated by run_invariant_checks() in 05b-customize-data.sql. Any critical FailCount > 0 breaks the build.';
COMMENT ON COLUMN invariant_checks.invariant_check_id IS 'Unique slug for this invariant (e.g. inv-balanced-alloc).';
COMMENT ON COLUMN invariant_checks.algebraic_statement IS 'The mathematical assertion in compact symbolic form.';
COMMENT ON COLUMN invariant_checks.natural_language IS 'Plain-English statement of what property must hold and why it is an invariant of the model.';
COMMENT ON COLUMN invariant_checks.source_table IS 'The DAG table whose rows are checked (TreatmentRankings or StratumSummaries).';
COMMENT ON COLUMN invariant_checks.filter_expression IS 'Condition selecting the universe of rows this invariant applies to. Empty means all rows.';
COMMENT ON COLUMN invariant_checks.assertion_expression IS 'The per-row condition that must be TRUE for every row in scope.';
COMMENT ON COLUMN invariant_checks.sql_filter IS 'Optional SQL WHERE clause that selects the universe of rows in scope for this invariant (e.g. distortion_type = ''D''). Empty string means all rows.';
COMMENT ON COLUMN invariant_checks.sql_assertion IS 'The SQL WHERE clause (without WHERE keyword) that counts PASSING rows from vw_treatment_rankings for this invariant. Used by run_invariant_checks() to evaluate each assertion dynamically from the rulebook table.';
COMMENT ON COLUMN invariant_checks.pass_count IS 'Rows where the invariant holds. Populated by 05b-customize-data.sql from a live query against vw_treatment_rankings.';
COMMENT ON COLUMN invariant_checks.fail_count IS 'Rows where the invariant is violated. Any FailCount > 0 is a build-breaking bug.';
COMMENT ON COLUMN invariant_checks.severity IS 'critical | warning — critical means any FailCount > 0 is a build-breaking bug.';
COMMENT ON COLUMN invariant_checks.tradition_id IS 'FK → ResearchTraditions.TraditionId. The tradition whose theoretical commitments this algebraic invariant protects — a failed invariant would falsify that tradition''s key claim.';
COMMENT ON COLUMN invariant_checks.protects_conclusion IS 'FK → Conclusions.ConclusionId. The conclusion whose witness depends on this invariant holding. If this invariant fails, that conclusion is undermined.';

-- ----------------------------------------------------------------------------
-- Methodology: Table: Methodology — the first-principles process used to build this domain model. Each row documents one methodological axiom or step. Together these rows let a reader (or an LLM) reconstruct why the model is shaped the way it is, and re-apply the same process to a new domain.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS methodology (
  methodology_id                      TEXT                 PRIMARY KEY          -- Unique slug (e.g. method-01-cmcc, method-02-dag-first).
);
ALTER TABLE methodology ADD COLUMN IF NOT EXISTS phase TEXT;                                        -- Broad phase: axiom | decomposition | derivation | hydration | validation | taxonomy | conclusion
ALTER TABLE methodology ADD COLUMN IF NOT EXISTS title TEXT;                                        -- Short title of the methodological principle or step.
ALTER TABLE methodology ADD COLUMN IF NOT EXISTS statement TEXT;                                    -- One-to-three sentence statement of the principle, precise enough to be applied or falsified.
ALTER TABLE methodology ADD COLUMN IF NOT EXISTS why_it_matters TEXT;                               -- Why this step or principle is load-bearing for this model — what breaks if you skip it.
ALTER TABLE methodology ADD COLUMN IF NOT EXISTS illustrated_by_loop TEXT;                          -- LoopId(s) where this principle was concretely demonstrated (comma-separated).
ALTER TABLE methodology ADD COLUMN IF NOT EXISTS tradition_id TEXT;                                 -- FK → ResearchTraditions.TraditionId. The scholarly tradition that introduced or most relies on this methodological approach.
ALTER TABLE methodology ADD COLUMN IF NOT EXISTS pioneering_researcher TEXT;                        -- FK → Researchers.ResearcherId. The researcher most associated with developing or popularising this methodological principle in the Simpson's Paradox context.
COMMENT ON TABLE methodology IS 'Table: Methodology — the first-principles process used to build this domain model. Each row documents one methodological axiom or step. Together these rows let a reader (or an LLM) reconstruct why the model is shaped the way it is, and re-apply the same process to a new domain.';
COMMENT ON COLUMN methodology.methodology_id IS 'Unique slug (e.g. method-01-cmcc, method-02-dag-first).';
COMMENT ON COLUMN methodology.phase IS 'Broad phase: axiom | decomposition | derivation | hydration | validation | taxonomy | conclusion';
COMMENT ON COLUMN methodology.title IS 'Short title of the methodological principle or step.';
COMMENT ON COLUMN methodology.statement IS 'One-to-three sentence statement of the principle, precise enough to be applied or falsified.';
COMMENT ON COLUMN methodology.why_it_matters IS 'Why this step or principle is load-bearing for this model — what breaks if you skip it.';
COMMENT ON COLUMN methodology.illustrated_by_loop IS 'LoopId(s) where this principle was concretely demonstrated (comma-separated).';
COMMENT ON COLUMN methodology.tradition_id IS 'FK → ResearchTraditions.TraditionId. The scholarly tradition that introduced or most relies on this methodological approach.';
COMMENT ON COLUMN methodology.pioneering_researcher IS 'FK → Researchers.ResearcherId. The researcher most associated with developing or popularising this methodological principle in the Simpson''s Paradox context.';

-- ----------------------------------------------------------------------------
-- Conclusions: Table: Conclusions — the substantive epistemic findings that this model has produced or is designed to produce. Each row is one conclusion: a claim about the domain, about the instrument, or about the methodology that is either already witnessed or is the target of a planned loop.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS conclusions (
  conclusion_id                       TEXT                 PRIMARY KEY          -- Unique slug (e.g. conc-01-paradox-is-derived).
);
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS category TEXT;                                     -- domain | instrument | methodology | open-question
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS status TEXT;                                       -- witnessed | planned | open
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS title TEXT;                                        -- One-line statement of the conclusion.
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS evidence TEXT;                                     -- The specific DB query result, loop outcome, or argument that establishes or will establish this conclusion.
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS witnessed_in_loop TEXT;                            -- LoopId where this conclusion was first witnessed (if status=witnessed).
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS target_loop TEXT;                                  -- LoopId that is designed to witness this conclusion (if status=planned).
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS tradition_id TEXT;                                 -- FK → ResearchTraditions.TraditionId. The tradition whose theoretical framework this conclusion primarily vindicates, refines, or challenges.
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS researcher_id TEXT;                                -- FK → Researchers.ResearcherId. The researcher whose specific claim, definition, or framework this conclusion directly affirms.
ALTER TABLE conclusions ADD COLUMN IF NOT EXISTS challenges_researcher TEXT;                        -- FK → Researchers.ResearcherId. A researcher whose position this conclusion refutes or qualifies (e.g. conc-03 refutes Blyth's unanimity criterion as the primary definition).
COMMENT ON TABLE conclusions IS 'Table: Conclusions — the substantive epistemic findings that this model has produced or is designed to produce. Each row is one conclusion: a claim about the domain, about the instrument, or about the methodology that is either already witnessed or is the target of a planned loop.';
COMMENT ON COLUMN conclusions.conclusion_id IS 'Unique slug (e.g. conc-01-paradox-is-derived).';
COMMENT ON COLUMN conclusions.category IS 'domain | instrument | methodology | open-question';
COMMENT ON COLUMN conclusions.status IS 'witnessed | planned | open';
COMMENT ON COLUMN conclusions.title IS 'One-line statement of the conclusion.';
COMMENT ON COLUMN conclusions.evidence IS 'The specific DB query result, loop outcome, or argument that establishes or will establish this conclusion.';
COMMENT ON COLUMN conclusions.witnessed_in_loop IS 'LoopId where this conclusion was first witnessed (if status=witnessed).';
COMMENT ON COLUMN conclusions.target_loop IS 'LoopId that is designed to witness this conclusion (if status=planned).';
COMMENT ON COLUMN conclusions.tradition_id IS 'FK → ResearchTraditions.TraditionId. The tradition whose theoretical framework this conclusion primarily vindicates, refines, or challenges.';
COMMENT ON COLUMN conclusions.researcher_id IS 'FK → Researchers.ResearcherId. The researcher whose specific claim, definition, or framework this conclusion directly affirms.';
COMMENT ON COLUMN conclusions.challenges_researcher IS 'FK → Researchers.ResearcherId. A researcher whose position this conclusion refutes or qualifies (e.g. conc-03 refutes Blyth''s unanimity criterion as the primary definition).';

-- ----------------------------------------------------------------------------
-- UIScreens: Table: UIScreens — the canonical screens that comprise the Simpson's Paradox Explorer UI. Each row defines one screen: its purpose, its primary data source (which rulebook view it reads), and the user action it supports. A developer can reconstruct the full UI from this table without any prior knowledge of the application.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS ui_screens (
  screen_id                           TEXT                 PRIMARY KEY          -- Unique slug (e.g. screen-01-study-list).
);
ALTER TABLE ui_screens ADD COLUMN IF NOT EXISTS title TEXT;                                         -- Human-readable screen title shown in the UI.
ALTER TABLE ui_screens ADD COLUMN IF NOT EXISTS route TEXT;                                         -- URL path pattern (e.g. /, /study/:studyId, /compare).
ALTER TABLE ui_screens ADD COLUMN IF NOT EXISTS primary_entity TEXT;                                -- The main rulebook entity this screen reads from (the vw_* view name without prefix).
ALTER TABLE ui_screens ADD COLUMN IF NOT EXISTS purpose TEXT;                                       -- One sentence: what a user can learn or do on this screen.
ALTER TABLE ui_screens ADD COLUMN IF NOT EXISTS key_fields TEXT;                                    -- Comma-separated list of the most important fields displayed on this screen.
ALTER TABLE ui_screens ADD COLUMN IF NOT EXISTS user_action TEXT;                                   -- Primary user action available on this screen (e.g. select a study, drill into a stratum).
ALTER TABLE ui_screens ADD COLUMN IF NOT EXISTS tradition_id TEXT;                                  -- FK → ResearchTraditions.TraditionId. The scholarly tradition whose lens this screen primarily serves — determines which framing language and which fields are most prominent.
ALTER TABLE ui_screens ADD COLUMN IF NOT EXISTS primary_conclusion TEXT;                            -- FK → Conclusions.ConclusionId. The conclusion this screen most directly visualises or communicates to the user.
COMMENT ON TABLE ui_screens IS 'Table: UIScreens — the canonical screens that comprise the Simpson''s Paradox Explorer UI. Each row defines one screen: its purpose, its primary data source (which rulebook view it reads), and the user action it supports. A developer can reconstruct the full UI from this table without any prior knowledge of the application.';
COMMENT ON COLUMN ui_screens.screen_id IS 'Unique slug (e.g. screen-01-study-list).';
COMMENT ON COLUMN ui_screens.title IS 'Human-readable screen title shown in the UI.';
COMMENT ON COLUMN ui_screens.route IS 'URL path pattern (e.g. /, /study/:studyId, /compare).';
COMMENT ON COLUMN ui_screens.primary_entity IS 'The main rulebook entity this screen reads from (the vw_* view name without prefix).';
COMMENT ON COLUMN ui_screens.purpose IS 'One sentence: what a user can learn or do on this screen.';
COMMENT ON COLUMN ui_screens.key_fields IS 'Comma-separated list of the most important fields displayed on this screen.';
COMMENT ON COLUMN ui_screens.user_action IS 'Primary user action available on this screen (e.g. select a study, drill into a stratum).';
COMMENT ON COLUMN ui_screens.tradition_id IS 'FK → ResearchTraditions.TraditionId. The scholarly tradition whose lens this screen primarily serves — determines which framing language and which fields are most prominent.';
COMMENT ON COLUMN ui_screens.primary_conclusion IS 'FK → Conclusions.ConclusionId. The conclusion this screen most directly visualises or communicates to the user.';

-- ----------------------------------------------------------------------------
-- UIComponents: Table: UIComponents — the reusable visual building blocks used across UIScreens. Each row defines one component: what it renders, which entity it reads, and what props it requires. A developer can implement the full UI by composing these components onto the screens defined in UIScreens.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS ui_components (
  component_id                        TEXT                 PRIMARY KEY          -- Unique slug (e.g. comp-01-distortion-badge).
);
ALTER TABLE ui_components ADD COLUMN IF NOT EXISTS component_name TEXT;                             -- Code-level component name (PascalCase, e.g. DistortionBadge).
