ALTER TABLE ui_components ADD COLUMN IF NOT EXISTS primary_entity TEXT;                             -- The rulebook entity this component reads (the vw_* view).
ALTER TABLE ui_components ADD COLUMN IF NOT EXISTS description TEXT;                                -- What this component renders and what decisions a developer must make to implement it.
ALTER TABLE ui_components ADD COLUMN IF NOT EXISTS required_fields TEXT;                            -- Comma-separated rulebook fields this component must receive as props.
ALTER TABLE ui_components ADD COLUMN IF NOT EXISTS visual_spec TEXT;                                -- Plain-English description of the visual output: shape, color coding, interactivity.
COMMENT ON TABLE ui_components IS 'Table: UIComponents — the reusable visual building blocks used across UIScreens. Each row defines one component: what it renders, which entity it reads, and what props it requires. A developer can implement the full UI by composing these components onto the screens defined in UIScreens.';
COMMENT ON COLUMN ui_components.component_id IS 'Unique slug (e.g. comp-01-distortion-badge).';
COMMENT ON COLUMN ui_components.component_name IS 'Code-level component name (PascalCase, e.g. DistortionBadge).';
COMMENT ON COLUMN ui_components.used_on_screens IS 'Comma-separated ScreenIds where this component appears.';
COMMENT ON COLUMN ui_components.primary_entity IS 'The rulebook entity this component reads (the vw_* view).';
COMMENT ON COLUMN ui_components.description IS 'What this component renders and what decisions a developer must make to implement it.';
COMMENT ON COLUMN ui_components.required_fields IS 'Comma-separated rulebook fields this component must receive as props.';
COMMENT ON COLUMN ui_components.visual_spec IS 'Plain-English description of the visual output: shape, color coding, interactivity.';

-- ----------------------------------------------------------------------------
-- InstrumentSpec: Table: InstrumentSpec — the complete specification of the Simpson's Paradox classification instrument. One row per component: required input fields, derived coordinates, classification outputs, and adapter requirements. Every row is machine-verifiable against the 238-study corpus. This table is the distillation of loops 1–25 into a reusable tool.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS instrument_spec (
  spec_id                             TEXT                 PRIMARY KEY          -- Unique identifier for this instrument component.
);
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS component_type TEXT;                           -- input | derived | classification | adapter-requirement
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS field_name TEXT;                               -- The field or variable name in the DAG.
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS data_type TEXT;                                -- integer | decimal | boolean | string | categorical
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS source_table TEXT;                             -- The DAG table where this field is computed or stored.
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS formula TEXT;                                  -- The ERB formula or derivation rule for this component.
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS natural_language TEXT;                         -- Plain-English statement of what this component represents or requires.
ALTER TABLE instrument_spec ADD COLUMN IF NOT EXISTS adapter_note TEXT;                             -- What a researcher must supply or verify to satisfy this component when hydrating a new study.
COMMENT ON TABLE instrument_spec IS 'Table: InstrumentSpec — the complete specification of the Simpson''s Paradox classification instrument. One row per component: required input fields, derived coordinates, classification outputs, and adapter requirements. Every row is machine-verifiable against the 238-study corpus. This table is the distillation of loops 1–25 into a reusable tool.';
COMMENT ON COLUMN instrument_spec.spec_id IS 'Unique identifier for this instrument component.';
COMMENT ON COLUMN instrument_spec.component_type IS 'input | derived | classification | adapter-requirement';
COMMENT ON COLUMN instrument_spec.field_name IS 'The field or variable name in the DAG.';
COMMENT ON COLUMN instrument_spec.data_type IS 'integer | decimal | boolean | string | categorical';
COMMENT ON COLUMN instrument_spec.source_table IS 'The DAG table where this field is computed or stored.';
COMMENT ON COLUMN instrument_spec.formula IS 'The ERB formula or derivation rule for this component.';
COMMENT ON COLUMN instrument_spec.natural_language IS 'Plain-English statement of what this component represents or requires.';
COMMENT ON COLUMN instrument_spec.adapter_note IS 'What a researcher must supply or verify to satisfy this component when hydrating a new study.';

-- ----------------------------------------------------------------------------
-- AllocationSweep: Table: AllocationSweep — parametric sweep of treatment-A allocation fraction within each study's most confounded stratum (see SweepStudyConfig). Ten fractions from 0.05 to 0.95 per study. SweepCorrectedGap is invariant; SweepPooledGap wanders.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS allocation_sweep (
  sweep_id                            TEXT                 PRIMARY KEY          -- Unique row identifier: <study>-f<pct> where pct is AllocFractionA*100.
);
ALTER TABLE allocation_sweep ADD COLUMN IF NOT EXISTS study_id TEXT;                                -- The study being swept — all 238 studies in the corpus.
ALTER TABLE allocation_sweep ADD COLUMN IF NOT EXISTS alloc_fraction_a NUMERIC;                     -- Fraction of the sweep-stratum cases assigned to treatment A. Ranges from 0.05 to 0.95. The sweep stratum is the one whose allocation was most confounded in the original study.
COMMENT ON TABLE allocation_sweep IS 'Table: AllocationSweep — parametric sweep of treatment-A allocation fraction within each study''s most confounded stratum (see SweepStudyConfig). Ten fractions from 0.05 to 0.95 per study. SweepCorrectedGap is invariant; SweepPooledGap wanders.';
COMMENT ON COLUMN allocation_sweep.sweep_id IS 'Unique row identifier: <study>-f<pct> where pct is AllocFractionA*100.';
COMMENT ON COLUMN allocation_sweep.study_id IS 'The study being swept — all 238 studies in the corpus.';
COMMENT ON COLUMN allocation_sweep.alloc_fraction_a IS 'Fraction of the sweep-stratum cases assigned to treatment A. Ranges from 0.05 to 0.95. The sweep stratum is the one whose allocation was most confounded in the original study.';

-- ----------------------------------------------------------------------------
-- SweepStudySummary: Table: SweepStudySummary
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS sweep_study_summary (
  sweep_study_id                      TEXT                 PRIMARY KEY          -- FK to Studies.StudyId. One row per study in the AllocationSweep.
);
COMMENT ON COLUMN sweep_study_summary.sweep_study_id IS 'FK to Studies.StudyId. One row per study in the AllocationSweep.';

-- ----------------------------------------------------------------------------
-- ResearchTraditions: Table: ResearchTraditions — the six scholarly lineages that have engaged with Simpson's Paradox. Each row is a named intellectual tradition, not a specific paper or result.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS research_traditions (
  tradition_id                        TEXT                 PRIMARY KEY          -- Slug identifier, e.g. tradition-historical.
);
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS name TEXT;                                 -- Short display name for the tradition.
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS era TEXT;                                  -- Approximate active period, e.g. "1899–1972".
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS core_concern TEXT;                         -- The central question this tradition asks about the paradox.
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS primary_venue TEXT;                        -- Where this tradition publishes (journal, conference, book series).
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS key_claim TEXT;                            -- The tradition's signature thesis or resolution strategy.
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS open_question TEXT;                        -- What this tradition leaves unresolved or contested.
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS verified_by_deep_research BOOLEAN;         -- True if the 2026-06-28 adversarial deep-research pass confirmed the tradition at high confidence.
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS illustrated_by_study TEXT;                 -- FK → Studies.StudyId. The study in this model that most vividly illustrates this tradition's characteristic concern or resolution strategy.
ALTER TABLE research_traditions ADD COLUMN IF NOT EXISTS supporting_conclusion TEXT;                -- FK → Conclusions.ConclusionId. The conclusion in this model that most directly validates or advances this tradition's central claim about Simpson's Paradox.
COMMENT ON TABLE research_traditions IS 'Table: ResearchTraditions — the six scholarly lineages that have engaged with Simpson''s Paradox. Each row is a named intellectual tradition, not a specific paper or result.';
COMMENT ON COLUMN research_traditions.tradition_id IS 'Slug identifier, e.g. tradition-historical.';
COMMENT ON COLUMN research_traditions.name IS 'Short display name for the tradition.';
COMMENT ON COLUMN research_traditions.era IS 'Approximate active period, e.g. "1899–1972".';
COMMENT ON COLUMN research_traditions.core_concern IS 'The central question this tradition asks about the paradox.';
COMMENT ON COLUMN research_traditions.primary_venue IS 'Where this tradition publishes (journal, conference, book series).';
COMMENT ON COLUMN research_traditions.key_claim IS 'The tradition''s signature thesis or resolution strategy.';
COMMENT ON COLUMN research_traditions.open_question IS 'What this tradition leaves unresolved or contested.';
COMMENT ON COLUMN research_traditions.verified_by_deep_research IS 'True if the 2026-06-28 adversarial deep-research pass confirmed the tradition at high confidence.';
COMMENT ON COLUMN research_traditions.illustrated_by_study IS 'FK → Studies.StudyId. The study in this model that most vividly illustrates this tradition''s characteristic concern or resolution strategy.';
COMMENT ON COLUMN research_traditions.supporting_conclusion IS 'FK → Conclusions.ConclusionId. The conclusion in this model that most directly validates or advances this tradition''s central claim about Simpson''s Paradox.';

-- ----------------------------------------------------------------------------
-- Researchers: Table: Researchers — individuals who have made named, verified contributions to understanding Simpson's Paradox. Linked to ResearchTraditions by TraditionId.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS researchers (
  researcher_id                       TEXT                 PRIMARY KEY          -- Slug, e.g. researcher-pearson.
);
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS name TEXT;                                         -- Full name as commonly cited.
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS tradition_id TEXT;                                 -- FK → ResearchTraditions.TraditionId
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS active_period TEXT;                                -- Approximate years of relevant work, e.g. "1899".
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS affiliation TEXT;                                  -- Primary institutional affiliation for the relevant work.
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS key_contribution TEXT;                             -- One-sentence description of their specific contribution to the paradox literature.
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS signature_work TEXT;                               -- The canonical paper or book most associated with their contribution.
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS relation_to_hannan_pearl TEXT;                     -- How this researcher's line of work relates to or differs from Hannan (aggregation bias) and Pearl (DAG/do-calculus).
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS verified_by_deep_research BOOLEAN;                 -- True if the 2026-06-28 adversarial deep-research pass confirmed this person at high confidence.
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS confidence_level TEXT;                             -- high | medium | unverified — matches deep-research vote outcome.
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS canonical_study_id TEXT;                           -- FK → Studies.StudyId. The study in this model that best illustrates this researcher's specific contribution to the Simpson's Paradox literature.
ALTER TABLE researchers ADD COLUMN IF NOT EXISTS illustrates_conclusion TEXT;                       -- FK → Conclusions.ConclusionId. The conclusion in this model that this researcher's work directly supports, challenges, or frames.
COMMENT ON TABLE researchers IS 'Table: Researchers — individuals who have made named, verified contributions to understanding Simpson''s Paradox. Linked to ResearchTraditions by TraditionId.';
COMMENT ON COLUMN researchers.researcher_id IS 'Slug, e.g. researcher-pearson.';
