COMMENT ON COLUMN researchers.illustrates_conclusion IS 'FK → Conclusions.ConclusionId. The conclusion in this model that this researcher''s work directly supports, challenges, or frames.';

-- ----------------------------------------------------------------------------
-- SyntheticPhase: Table: SyntheticPhase — a parametric grid of canonical 2×2 synthetic studies at controlled (ParamStratumFraction, ParamStratumGap1, ParamStratumGap2, ParamAllocationBias) coordinates. Stratum 1 is the hard stratum (base rate 0.45); stratum 2 is easy (base rate 0.75). Each row constructs cell counts from the parameters and derives PhaseDistortionType using the same geometric classification as TreatmentRankings. This maps the A/B/C+/C-/D phase boundaries algebraically — independent of empirical corpus data.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS synthetic_phase (
  phase_id                            TEXT                 PRIMARY KEY          -- Unique grid-point identifier encoding (w, g1, g2, b) coordinates.
);
ALTER TABLE synthetic_phase ADD COLUMN IF NOT EXISTS param_stratum_fraction NUMERIC;                -- w — fraction of total cases in the hard (stratum-1) subgroup. Range 0.30–0.75 in this grid.
ALTER TABLE synthetic_phase ADD COLUMN IF NOT EXISTS param_stratum_gap1 NUMERIC;                    -- g1 — signed treatment advantage (rate_A − rate_B) in the hard stratum. Positive means A wins stratum 1.
ALTER TABLE synthetic_phase ADD COLUMN IF NOT EXISTS param_stratum_gap2 NUMERIC;                    -- g2 — signed treatment advantage in the easy stratum. Negative g2 enables type-B (partial reversal) cells.
ALTER TABLE synthetic_phase ADD COLUMN IF NOT EXISTS param_allocation_bias NUMERIC;                 -- b — allocation bias in stratum 1: extra fraction of stratum-1 cases assigned to treatment A above 50/50. Range 0.00–0.95.
COMMENT ON TABLE synthetic_phase IS 'Table: SyntheticPhase — a parametric grid of canonical 2×2 synthetic studies at controlled (ParamStratumFraction, ParamStratumGap1, ParamStratumGap2, ParamAllocationBias) coordinates. Stratum 1 is the hard stratum (base rate 0.45); stratum 2 is easy (base rate 0.75). Each row constructs cell counts from the parameters and derives PhaseDistortionType using the same geometric classification as TreatmentRankings. This maps the A/B/C+/C-/D phase boundaries algebraically — independent of empirical corpus data.';
COMMENT ON COLUMN synthetic_phase.phase_id IS 'Unique grid-point identifier encoding (w, g1, g2, b) coordinates.';
COMMENT ON COLUMN synthetic_phase.param_stratum_fraction IS 'w — fraction of total cases in the hard (stratum-1) subgroup. Range 0.30–0.75 in this grid.';
COMMENT ON COLUMN synthetic_phase.param_stratum_gap1 IS 'g1 — signed treatment advantage (rate_A − rate_B) in the hard stratum. Positive means A wins stratum 1.';
COMMENT ON COLUMN synthetic_phase.param_stratum_gap2 IS 'g2 — signed treatment advantage in the easy stratum. Negative g2 enables type-B (partial reversal) cells.';
COMMENT ON COLUMN synthetic_phase.param_allocation_bias IS 'b — allocation bias in stratum 1: extra fraction of stratum-1 cases assigned to treatment A above 50/50. Range 0.00–0.95.';

-- ----------------------------------------------------------------------------
-- PhaseDiagramSummary: Table: PhaseDiagramSummary — one row summarising the SyntheticPhase grid. Witnesses that all five DistortionType cells (A, B, C+, C-, D) are nonempty in parameter space.
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS phase_diagram_summary (
  phase_diagram_id                    TEXT                 PRIMARY KEY          -- Unique identifier for this phase diagram instance.
);
ALTER TABLE phase_diagram_summary ADD COLUMN IF NOT EXISTS phase_type_a_count INTEGER;              -- Grid points classified as type A. Populated from vw_synthetic_phase by 05b-customize-data.sql.
ALTER TABLE phase_diagram_summary ADD COLUMN IF NOT EXISTS phase_type_b_count INTEGER;              -- Grid points classified as type B. Populated from vw_synthetic_phase by 05b-customize-data.sql.
ALTER TABLE phase_diagram_summary ADD COLUMN IF NOT EXISTS phase_type_c_plus_count INTEGER;         -- Grid points classified as type C+. Populated from vw_synthetic_phase by 05b-customize-data.sql.
ALTER TABLE phase_diagram_summary ADD COLUMN IF NOT EXISTS phase_type_c_minus_count INTEGER;        -- Grid points classified as type C-. Populated from vw_synthetic_phase by 05b-customize-data.sql.
ALTER TABLE phase_diagram_summary ADD COLUMN IF NOT EXISTS phase_type_d_count INTEGER;              -- Grid points classified as type D. Populated from vw_synthetic_phase by 05b-customize-data.sql.
COMMENT ON TABLE phase_diagram_summary IS 'Table: PhaseDiagramSummary — one row summarising the SyntheticPhase grid. Witnesses that all five DistortionType cells (A, B, C+, C-, D) are nonempty in parameter space.';
COMMENT ON COLUMN phase_diagram_summary.phase_diagram_id IS 'Unique identifier for this phase diagram instance.';
COMMENT ON COLUMN phase_diagram_summary.phase_type_a_count IS 'Grid points classified as type A. Populated from vw_synthetic_phase by 05b-customize-data.sql.';
COMMENT ON COLUMN phase_diagram_summary.phase_type_b_count IS 'Grid points classified as type B. Populated from vw_synthetic_phase by 05b-customize-data.sql.';
COMMENT ON COLUMN phase_diagram_summary.phase_type_c_plus_count IS 'Grid points classified as type C+. Populated from vw_synthetic_phase by 05b-customize-data.sql.';
