-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS sweep_study_config (
  config_id                           TEXT                 PRIMARY KEY          -- Unique slug; mirrors StudyId.
);
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS study_id TEXT;                              -- FK to Studies.StudyId.
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS sweep_stratum_label TEXT;                   -- Stratum whose A/B allocation is swept (highest |AllocationBias| in original data).
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS n_sweep_stratum_total NUMERIC;              -- Total cases in the sweep stratum (fixed across sweep rows).
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS sweep_rate_a NUMERIC;                       -- Success rate for treatment A in the sweep stratum.
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS sweep_rate_b NUMERIC;                       -- Success rate for treatment B in the sweep stratum.
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS n_fixed_a NUMERIC;                          -- A cases in all non-swept strata (fixed).
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS n_fixed_b NUMERIC;                          -- B cases in all non-swept strata (fixed).
