ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS fixed_rate_b NUMERIC;                       -- Weighted success rate for B in fixed strata.
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS original_alloc_fraction_a NUMERIC;          -- Observed fraction of sweep-stratum cases assigned to treatment A.
ALTER TABLE sweep_study_config ADD COLUMN IF NOT EXISTS sweep_corrected_gap NUMERIC;                -- Allocation-free gap: sum_s (n_s/N)*(rate_As-rate_Bs). Invariant under within-stratum reallocation.
COMMENT ON TABLE sweep_study_config IS 'Table: SweepStudyConfig — per-study allocation-sweep parameters derived from CaseCells. Picks the highest-allocation-bias stratum to sweep; holds all other strata fixed.';
