COMMENT ON COLUMN sweep_study_config.sweep_rate_a IS 'Success rate for treatment A in the sweep stratum.';
COMMENT ON COLUMN sweep_study_config.sweep_rate_b IS 'Success rate for treatment B in the sweep stratum.';
COMMENT ON COLUMN sweep_study_config.n_fixed_a IS 'A cases in all non-swept strata (fixed).';
COMMENT ON COLUMN sweep_study_config.n_fixed_b IS 'B cases in all non-swept strata (fixed).';
COMMENT ON COLUMN sweep_study_config.fixed_rate_a IS 'Weighted success rate for A in fixed strata.';
COMMENT ON COLUMN sweep_study_config.fixed_rate_b IS 'Weighted success rate for B in fixed strata.';
COMMENT ON COLUMN sweep_study_config.original_alloc_fraction_a IS 'Observed fraction of sweep-stratum cases assigned to treatment A.';
COMMENT ON COLUMN sweep_study_config.sweep_corrected_gap IS 'Allocation-free gap: sum_s (n_s/N)*(rate_As-rate_Bs). Invariant under within-stratum reallocation.';

-- ----------------------------------------------------------------------------
-- SubstrateConformanceFields: Table: SubstrateConformanceFields — cross-substrate OWL-SHACL vs Postgres compare manifest for owl/reason.py. Rows with AssertFromPostgres=TRUE are asserted as leaf facts before SHACL fixpoint (OWL transpiler lacks CONSTRUCT for nested IF chains).
-- ----------------------------------------------------------------------------
CREATE TABLE IF NOT EXISTS substrate_conformance_fields (
  field_id                            TEXT                 PRIMARY KEY          -- Unique slug.
);
ALTER TABLE substrate_conformance_fields ADD COLUMN IF NOT EXISTS source_table TEXT;                -- TreatmentRankings | StratumSummaries | StratumVariables
ALTER TABLE substrate_conformance_fields ADD COLUMN IF NOT EXISTS field_name TEXT;                  -- PascalCase rulebook field name.
ALTER TABLE substrate_conformance_fields ADD COLUMN IF NOT EXISTS pg_column TEXT;                   -- snake_case vw_* column.
ALTER TABLE substrate_conformance_fields ADD COLUMN IF NOT EXISTS owl_local_name TEXT;              -- camelCase OWL property local name.
ALTER TABLE substrate_conformance_fields ADD COLUMN IF NOT EXISTS data_type TEXT;                   -- float | int | bool | str
ALTER TABLE substrate_conformance_fields ADD COLUMN IF NOT EXISTS assert_from_postgres BOOLEAN;     -- TRUE when OWL cannot derive this field yet and Postgres value is asserted before SHACL fixpoint.
ALTER TABLE substrate_conformance_fields ADD COLUMN IF NOT EXISTS in_compare_set BOOLEAN;           -- TRUE when reason.py diffs this field between substrates.
COMMENT ON TABLE substrate_conformance_fields IS 'Table: SubstrateConformanceFields — cross-substrate OWL-SHACL vs Postgres compare manifest for owl/reason.py. Rows with AssertFromPostgres=TRUE are asserted as leaf facts before SHACL fixpoint (OWL transpiler lacks CONSTRUCT for nested IF chains).';
COMMENT ON COLUMN substrate_conformance_fields.field_id IS 'Unique slug.';
COMMENT ON COLUMN substrate_conformance_fields.source_table IS 'TreatmentRankings | StratumSummaries | StratumVariables';
COMMENT ON COLUMN substrate_conformance_fields.field_name IS 'PascalCase rulebook field name.';
COMMENT ON COLUMN substrate_conformance_fields.pg_column IS 'snake_case vw_* column.';
COMMENT ON COLUMN substrate_conformance_fields.owl_local_name IS 'camelCase OWL property local name.';
COMMENT ON COLUMN substrate_conformance_fields.data_type IS 'float | int | bool | str';
COMMENT ON COLUMN substrate_conformance_fields.assert_from_postgres IS 'TRUE when OWL cannot derive this field yet and Postgres value is asserted before SHACL fixpoint.';
COMMENT ON COLUMN substrate_conformance_fields.in_compare_set IS 'TRUE when reason.py diffs this field between substrates.';

